```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create table if it doesn't exist
  auto create_result = (sqlgen::create_table<T> | sqlgen::if_not_exists)(conn);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // Insert records
  auto insert_result = sqlgen::insert(records)(conn);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to their respective structs and primary key columns
  std::map<std::string, std::pair<rfl::TupleType, std::string>> table_map = {
    {"Student", {rfl::tuple_type<Student>, "SNo"}},
    {"Course", {rfl::tuple_type<Course>, "CID"}},
    {"Score", {rfl::tuple_type<Score>, "ScID"}},
    {"Major", {rfl::tuple_type<Major>, "MID"}}
  };

  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::runtime_error("Invalid table name");
  }

  auto [record_type, pk_column] = it->second;

  // Convert record_id to appropriate type based on primary key
  if (record_type == rfl::tuple_type<Student>) {
    // SNo is Varchar<10> - use as string
    auto delete_result = (sqlgen::delete_from<Student> | sqlgen::where("SNo"_c == record_id))(conn);
    if (!delete_result) {
      throw std::runtime_error("Failed to delete from Student");
    }
  } else {
    // Other primary keys are numeric - convert from string
    uint32_t id;
    try {
      id = std::stoul(record_id);
    } catch (...) {
      throw std::runtime_error("Invalid numeric record ID");
    }

    if (record_type == rfl::tuple_type<Course>) {
      auto delete_result = (sqlgen::delete_from<Course> | sqlgen::where("CID"_c == id))(conn);
      if (!delete_result) {
        throw std::runtime_error("Failed to delete from Course");
      }
    } else if (record_type == rfl::tuple_type<Score>) {
      auto delete_result = (sqlgen::delete_from<Score> | sqlgen::where("ScID"_c == id))(conn);
      if (!delete_result) {
        throw std::runtime_error("Failed to delete from Score");
      }
    } else if (record_type == rfl::tuple_type<Major>) {
      auto delete_result = (sqlgen::delete_from<Major> | sqlgen::where("MID"_c == id))(conn);
      if (!delete_result) {
        throw std::runtime_error("Failed to delete from Major");
      }
    }
  }
}
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to `data/eas_database.db`

2. **Table Creation**: Uses `sqlgen::create_table<T> | sqlgen::if_not_exists` pattern to create tables only if they don't exist

3. **Record Insertion**: Uses `sqlgen::insert()` function to insert the provided records

4. **Primary Key Handling**: 
   - Student uses `SNo` (Varchar<10>) as string
   - Course, Score, Major use numeric primary keys (converted from string)

5. **Error Handling**: Throws exceptions on connection failures, table creation failures, and insertion failures

6. **Table Mapping**: Uses a map to associate table names with their corresponding structs and primary key columns

7. **Type Safety**: Properly handles type conversions between string parameters and actual primary key types

The implementation follows sqlgen best practices by using the fluent API with `operator|` for chaining operations and properly handles the different primary key types across the various tables in the EAS database.

