namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Perform upsert operation using write with if_exists modifier
  auto write_op = sqlgen::write(items) | sqlgen::if_exists;
  auto write_result = write_op(conn);
  if (!write_result) {
    return false;
  }

  // Read back items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false;
  }

  auto read_items = *read_result;

  // Verify that the number of items matches
  if (read_items.size() != items.size()) {
    return false;
  }

  // Verify each item's data
  for (size_t i = 0; i < items.size(); ++i) {
    if (read_items[i].item_id != items[i].item_id ||
        read_items[i].name != items[i].name ||
        read_items[i].quantity != items[i].quantity) {
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
