```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Use sqlgen::read to query the UserProfile table
  // 3. Apply ltrim, rtrim, and trim operations on name and email columns
  // 4. Compute length of trimmed strings
  // 5. Map results to ValidatedProfile struct
  return sqlgen::read<std::vector<ValidatedProfile>>(
      conn,
      sqlgen::ltrim(sqlgen::Col<"name">{}),
      sqlgen::rtrim(sqlgen::Col<"email">{})
  ).transform([](auto&& profiles) {
    std::vector<ValidatedProfile> result;
    for (auto& profile : profiles) {
      // Apply trim operation (combination of ltrim and rtrim)
      profile.trimmed_name = sqlgen::trim(sqlgen::Col<"name">{})();
      profile.trimmed_email = sqlgen::trim(sqlgen::Col<"email">{})();

      // Compute lengths
      profile.name_length = sqlgen::length(profile.trimmed_name);
      profile.email_length = sqlgen::length(profile.trimmed_email);

      result.push_back(std::move(profile));
    }
    return result;
  }).value();
}

}  // namespace trim_and_length_validation
